import{_ as t,o as a,c as d,a2 as o}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 22 — Visual Mode: Character Selection","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/22-visual-mode-character.md","filePath":"chapters/22-visual-mode-character.md"}'),n={name:"chapters/22-visual-mode-character.md"};function r(i,e,c,s,l,h){return a(),d("div",null,[...e[0]||(e[0]=[o(`<h1 id="chapter-22-—-visual-mode-character-selection" tabindex="-1">Chapter 22 — Visual Mode: Character Selection <a class="header-anchor" href="#chapter-22-—-visual-mode-character-selection" aria-label="Permalink to &quot;Chapter 22 — Visual Mode: Character Selection&quot;">​</a></h1><blockquote><p><em>&quot;Visual mode makes Vim&#39;s text selection visible and intuitive.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Visual mode shows you exactly what text you&#39;re selecting.</p><p>There are three variants:</p><ul><li>Character-wise (<code>v</code>)</li><li>Line-wise (<code>V</code>)</li><li>Block-wise (<code>Ctrl+v</code>)</li></ul><hr><h1 id="character-wise-visual-mode" tabindex="-1">Character-Wise Visual Mode <a class="header-anchor" href="#character-wise-visual-mode" aria-label="Permalink to &quot;Character-Wise Visual Mode&quot;">​</a></h1><p>Press <code>v</code> to enter character-wise visual mode.</p><p>Move the cursor to extend the selection.</p><h2 id="entering" tabindex="-1">Entering <a class="header-anchor" href="#entering" aria-label="Permalink to &quot;Entering&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v       →   Start character selection</span></span></code></pre></div><h2 id="extending-selection" tabindex="-1">Extending Selection <a class="header-anchor" href="#extending-selection" aria-label="Permalink to &quot;Extending Selection&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>h</code>/<code>l</code></td><td>Extend left/right</td></tr><tr><td><code>j</code>/<code>k</code></td><td>Extend down/up</td></tr><tr><td><code>w</code></td><td>Extend to next word</td></tr><tr><td><code>b</code></td><td>Extend back one word</td></tr><tr><td><code>e</code></td><td>Extend to end of word</td></tr><tr><td><code>0</code></td><td>Extend to line beginning</td></tr><tr><td><code>$</code></td><td>Extend to line end</td></tr><tr><td><code>G</code></td><td>Extend to end of file</td></tr><tr><td><code>gg</code></td><td>Extend to start of file</td></tr></tbody></table><hr><h1 id="actions-on-selection" tabindex="-1">Actions on Selection <a class="header-anchor" href="#actions-on-selection" aria-label="Permalink to &quot;Actions on Selection&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>d</code></td><td>Delete selection</td></tr><tr><td><code>x</code></td><td>Delete selection</td></tr><tr><td><code>y</code></td><td>Yank (copy) selection</td></tr><tr><td><code>c</code></td><td>Change selection (delete + insert)</td></tr><tr><td><code>~</code></td><td>Swap case</td></tr><tr><td><code>u</code></td><td>Make lowercase</td></tr><tr><td><code>U</code></td><td>Make uppercase</td></tr><tr><td><code>&gt;</code></td><td>Indent right</td></tr><tr><td><code>&lt;</code></td><td>Indent left</td></tr><tr><td><code>J</code></td><td>Join lines into one</td></tr><tr><td><code>Esc</code></td><td>Exit visual mode</td></tr></tbody></table><hr><h1 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The quick brown fox jumps over the lazy dog.</span></span>
<span class="line"><span>         ^ cursor</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press v, then press w three times:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The quick brown fox jumps over the lazy dog.</span></span>
<span class="line"><span>^^^^^^^^^^^^^^^ selected</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press d:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The fox jumps over the lazy dog.</span></span></code></pre></div><hr><h1 id="exiting-visual-mode" tabindex="-1">Exiting Visual Mode <a class="header-anchor" href="#exiting-visual-mode" aria-label="Permalink to &quot;Exiting Visual Mode&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Esc</code></td><td>Exit visual mode</td></tr><tr><td><code>Ctrl+c</code></td><td>Exit visual mode</td></tr><tr><td><code>v</code></td><td>Toggle back to normal</td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>v</code></td><td>Enter character visual mode</td></tr><tr><td>Move keys</td><td>Extend selection</td></tr><tr><td><code>d</code></td><td>Delete selection</td></tr><tr><td><code>y</code></td><td>Yank selection</td></tr><tr><td><code>c</code></td><td>Change selection</td></tr><tr><td><code>~</code></td><td>Toggle case</td></tr><tr><td><code>Esc</code></td><td>Exit visual mode</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>v</code> enters character-wise visual mode.</li><li>Move with any normal mode motion to extend selection.</li><li><code>d</code>, <code>y</code>, <code>c</code> operate on the selection.</li><li><code>Esc</code> exits back to normal mode.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and select a few words with <code>v</code> and <code>w</code>.</li><li>Delete the selection with <code>d</code>.</li><li>Select text and yank it with <code>y</code>, then paste with <code>p</code>.</li><li>Select text and change its case with <code>~</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./23-visual-mode-line.html"><strong>Chapter 23 — Visual Mode: Line Selection</strong></a></p><p>Select entire lines in visual mode for efficient line-based editing.</p>`,39)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
